class Solution:
    def numGoodSubarrays(self, nums, k):
        seen = set()
        n = len(nums)
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                if s % k == 0:
                    seen.add(tuple(nums[i:j + 1]))
        return len(seen)

