var numGoodSubarrays = function(nums, k) {
    const runs = [];
    let i = 0;
    const n = nums.length;
    while (i < n) {
        let j = i;
        while (j < n && nums[j] === nums[i]) j++;
        runs.push([nums[i], j - i]);
        i = j;
    }
    const R = runs.length;
    let count = 0;
    for (let a = 0; a < R; a++) {
        const va = runs[a][0], ca = runs[a][1];
        for (let L = 1; L <= ca; L++) {
            if ((va * L) % k === 0) count++;
        }
        let midSum = 0;
        for (let b = a + 1; b < R; b++) {
            const vb = runs[b][0], cb = runs[b][1];
            for (let ua = 1; ua <= ca; ua++) {
                for (let ub = 1; ub <= cb; ub++) {
                    const total = ua * va + midSum + ub * vb;
                    if (total % k === 0) count++;
                }
            }
            midSum += vb * cb;
        }
    }
    return count;
};
